external_knowledge:
- "sprinkle the magic of dividends" refers to companies paying dividends;
- "touch the skies" metaphorically means reaching a significant proportion of their market capitalization (in this case, 5%);
- "financial constellations" refers to the market indices or financial market where these companies are listed.

sql:
SELECT AVG(change) AS avg_change, AVG(percentage_change) AS avg_percentage_change
FROM daily_prices
WHERE change > 1;

SELECT ticker, company_name, market_cap AS max_market_value
FROM stocks
ORDER BY market_cap DESC;

SELECT * 
FROM market_indices 
WHERE index_name = 'S&P 500' AND change > 0;

external_knowledge:
- 'people tracking' refers to users who have set price alerts;
- 'latest prices' refers to the most recent closing price of the stocks;
- 'crossed their set thresholds to the upside' indicates the alert type is 'above' and the stock's closing price is higher than the alert's price threshold.

sql:
SELECT AVG(average_price)
FROM historical_prices
WHERE year = 2020;

SELECT index_name, MAX(market_cap) AS max_market_cap
FROM market_indices
GROUP BY index_name;

SELECT h.stock_id, h.average_price AS average_historical_price
FROM historical_prices h
INNER JOIN daily_prices dp ON h.stock_id = dp.stock_id
WHERE h.average_price > (
    SELECT AVG(last_value) FROM market_indices
);
